import { Link, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import { toast } from "react-toastify";

export default function Navbar({ authState, setAuthState }) {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const navigate = useNavigate();

  // Use authState from props instead of local state
  const currentUser = authState?.currentUser;
  const isAuthenticated = authState?.isAuthenticated;

  useEffect(() => {
    // Listen for auth changes from other components
    const handleAuthChange = () => {
      const user = localStorage.getItem("currentUser");
      const token = localStorage.getItem("authToken");
      if (setAuthState) {
        setAuthState({
          isAuthenticated: !!(user && token),
          currentUser: user ? JSON.parse(user) : null
        });
      }
    };

    window.addEventListener('authChange', handleAuthChange);
    window.addEventListener('storage', handleAuthChange);

    return () => {
      window.removeEventListener('authChange', handleAuthChange);
      window.removeEventListener('storage', handleAuthChange);
    };
  }, [setAuthState]);

  const handleLogout = () => {
    localStorage.removeItem("currentUser");
    localStorage.removeItem("authToken");
    setIsUserMenuOpen(false);
    
    // Update auth state
    if (setAuthState) {
      setAuthState({
        isAuthenticated: false,
        currentUser: null
      });
    }
    
    // Dispatch event to notify other components
    window.dispatchEvent(new Event('authChange'));
    
    toast.success("Logged out successfully!");
    navigate("/");
  };

  return (
    <nav className="bg-gradient-to-r from-slate-900 via-slate-800 to-slate-900 text-white p-4 font-semibold shadow-lg sticky top-0 z-50 border-b border-slate-700">
      <div className="container mx-auto flex justify-between items-center">
        <Link to="/" className="text-xl font-bold flex items-center group">
          <div className="w-10 h-10 bg-gradient-to-br from-emerald-400 to-cyan-500 rounded-lg flex items-center justify-center mr-3 group-hover:scale-110 transition-transform duration-300">
            <span className="text-xl">📊</span>
          </div>
          <div>
            <span className="text-2xl font-extrabold bg-gradient-to-r from-emerald-400 to-cyan-400 bg-clip-text text-transparent">
              Stock Broker Pro
            </span>
            <p className="text-xs text-slate-400 font-normal">Your Wealth Partner</p>
          </div>
        </Link>
        
        {/* Desktop Menu */}
        <div className="hidden md:flex items-center space-x-8">
          <Link to="/" className="hover:text-emerald-400 transition-colors duration-200 text-sm uppercase tracking-wide">
            Home
          </Link>
          
          {/* Show Dashboard only after login */}
          {currentUser && (
            <>
              <Link to="/dashboard" className="hover:text-emerald-400 transition-colors duration-200 text-sm uppercase tracking-wide">
                Dashboard
              </Link>
              <Link to="/markets" className="hover:text-emerald-400 transition-colors duration-200 text-sm uppercase tracking-wide">
                Markets
              </Link>
              <Link to="/watchlist" className="hover:text-emerald-400 transition-colors duration-200 text-sm uppercase tracking-wide">
                Watchlist
              </Link>
              <Link to="/portfolio" className="hover:text-emerald-400 transition-colors duration-200 text-sm uppercase tracking-wide">
                Portfolio
              </Link>
            </>
          )}

          <div className="flex items-center space-x-4 ml-4">
            {currentUser ? (
              /* User Profile Dropdown - Show after login */
              <div className="relative">
                <button
                  onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
                  className="flex items-center space-x-2 px-4 py-2 bg-slate-700 rounded-full hover:bg-slate-600 transition-colors"
                >
                  <div className="w-8 h-8 bg-gradient-to-br from-emerald-400 to-cyan-500 rounded-full flex items-center justify-center">
                    <span className="text-sm font-bold text-slate-900">
                      {currentUser.name ? currentUser.name.charAt(0).toUpperCase() : "U"}
                    </span>
                  </div>
                  <span className="text-sm">{currentUser.name || "User"}</span>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                  </svg>
                </button>

                {/* Dropdown Menu */}
                {isUserMenuOpen && (
                  <div className="absolute right-0 mt-2 w-56 bg-slate-800 rounded-xl shadow-2xl border border-slate-700 py-2">
                    <div className="px-4 py-2 border-b border-slate-700">
                      <p className="text-sm font-semibold">{currentUser.name}</p>
                      <p className="text-xs text-slate-400">{currentUser.email}</p>
                      {/* Backend TODO: Show user's wallet balance from database */}
                      <p className="text-xs text-emerald-400 mt-1">Wallet: ₹10,000</p>
                    </div>
                    <Link
                      to="/dashboard"
                      onClick={() => setIsUserMenuOpen(false)}
                      className="block px-4 py-2 hover:bg-slate-700 transition-colors"
                    >
                      <div className="flex items-center">
                        <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
                        </svg>
                        Dashboard
                      </div>
                    </Link>
                    <Link
                      to="/portfolio"
                      onClick={() => setIsUserMenuOpen(false)}
                      className="block px-4 py-2 hover:bg-slate-700 transition-colors"
                    >
                      <div className="flex items-center">
                        <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                        </svg>
                        My Portfolio
                      </div>
                    </Link>
                    <Link
                      to="/watchlist"
                      onClick={() => setIsUserMenuOpen(false)}
                      className="block px-4 py-2 hover:bg-slate-700 transition-colors"
                    >
                      <div className="flex items-center">
                        <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" />
                        </svg>
                        Watchlist
                      </div>
                    </Link>
                    {/* Backend TODO: Add profile settings page */}
                    <Link
                      to="/settings"
                      onClick={() => setIsUserMenuOpen(false)}
                      className="block px-4 py-2 hover:bg-slate-700 transition-colors"
                    >
                      <div className="flex items-center">
                        <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                        </svg>
                        Settings
                      </div>
                    </Link>
                    <hr className="my-2 border-slate-700" />
                    <button
                      onClick={handleLogout}
                      className="block w-full text-left px-4 py-2 hover:bg-slate-700 transition-colors text-red-400"
                    >
                      <div className="flex items-center">
                        <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                        </svg>
                        Logout
                      </div>
                    </button>
                  </div>
                )}
              </div>
            ) : (
              /* Show Login/Register buttons when not logged in */
              <>
                <Link 
                  to="/login" 
                  className="px-5 py-2 text-sm font-semibold hover:text-emerald-400 transition-colors duration-200"
                >
                  Login
                </Link>
                <Link 
                  to="/register" 
                  className="bg-gradient-to-r from-emerald-500 to-cyan-500 text-slate-900 px-5 py-2 rounded-full text-sm font-bold hover:shadow-lg hover:shadow-emerald-500/30 transition-all duration-300 transform hover:-translate-y-0.5"
                >
                  Open Account
                </Link>
              </>
            )}
          </div>
        </div>

        {/* Mobile Menu Button */}
        <button 
          className="md:hidden"
          onClick={() => setIsMenuOpen(!isMenuOpen)}
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            {isMenuOpen ? (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            ) : (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
            )}
          </svg>
        </button>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden mt-4 pb-4 space-y-3 border-t border-slate-700 pt-4">
          <Link to="/" className="block hover:text-emerald-400 transition-colors duration-200">Home</Link>
          
          {currentUser ? (
            <>
              <Link to="/dashboard" className="block hover:text-emerald-400 transition-colors duration-200">Dashboard</Link>
              <Link to="/markets" className="block hover:text-emerald-400 transition-colors duration-200">Markets</Link>
              <Link to="/watchlist" className="block hover:text-emerald-400 transition-colors duration-200">Watchlist</Link>
              <Link to="/portfolio" className="block hover:text-emerald-400 transition-colors duration-200">Portfolio</Link>
              <hr className="border-slate-700" />
              <div className="px-2 py-2">
                <p className="text-sm text-slate-400">Logged in as: {currentUser.name}</p>
              </div>
              <button
                onClick={handleLogout}
                className="block w-full text-left text-red-400 hover:text-red-300 transition-colors duration-200"
              >
                Logout
              </button>
            </>
          ) : (
            <>
              <Link to="/login" className="block hover:text-emerald-400 transition-colors duration-200">Login</Link>
              <Link to="/register" className="block bg-gradient-to-r from-emerald-500 to-cyan-500 text-slate-900 px-5 py-2 rounded-lg text-center font-bold">
                Open Account
              </Link>
            </>
          )}
        </div>
      )}
    </nav>
  );
}
